var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"수습 요원 자격을 만족했군요. 축하합니다. 로이 버넷.","JPN":"インターン・エージェントとしての資格を満たしました。\\nおめでとうございます、ロイ・バーネット。","ENG":"So you've met the prerequisites to become a probationary agent. Congratulations. Roy Burnett.","TWN":"你達到實習特工資格了，恭喜你，羅伊·伯內特。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"애송이 티를 벗으려면 아직 갈 길이 멀지만 말이야.","JPN":"一人前になるまで、まだ先は長いけどな。","ENG":"The lad's still got long ways to go till he stops smelling like an FNG.","TWN":"不過要褪去這一身乳臭味，還差得遠呢。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헹. 양로원에 들어갈 때도 그런 소리가 나오나 보자고, 할배.","JPN":"へッ。介護施設に入る時は、そんなこと言ってられなくなるぜ、ジジイ？","ENG":"Heh. Let's see if you'll still be running your mouth like that when you're in a rest home, old chap.","TWN":"哼，等你進養老院時，看你還能不能說出這種話，老頭。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 마음 편히 일 맡기고 은퇴할 수 있다면 나야 환영이지.","JPN":"はは。安心して仕事を任せて引退できるなら、俺は大歓迎だ。","ENG":"Hah hah, I'd welcome the day I can retire in peace in a heartbeat. So long as I know I can count on you.","TWN":"哈哈，要是能放心地把工作交給你然後隱退，我當然樂意了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 갑작스럽겠지만, 다음 임무입니다.","JPN":"それでは、急ですが次の任務です。","ENG":"I hate interrupting this merry banter, but I must brief the young agent on his next mission.","TWN":"那個不好意思，下個任務來了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭔데? 홍차 폭탄한테 시달리는 일만 아니면 까짓 거 뭐라도 상관없어.","JPN":"何だ？　紅茶爆弾に叩きのめされること以外なら、何だって構わないぜ。","ENG":"What is it? I'm up for anything as long as I don't have to deal with the Tea Bomb.","TWN":"是什麼？只要不是被紅茶炸彈折磨，什麼工作我都願意接。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 오랜 적수와의 전면전에 대비해 믿을 만한 협력자를 찾고 있습니다.","JPN":"本機関は敵との全面戦に備えて、信頼できる協力者を探しています。","ENG":"The Institution is seeking a reliable partner to prepare for an all-out war against a long-standing enemy.","TWN":"為了應對與老對頭的全面戰爭，正在尋找可靠的合作者。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"실력은 뛰어나면서, 대외적으로는 아직 부각되지 않은 조직이라면 더욱 좋죠.","JPN":"腕が立つと同時に対外的にはまだ知られていない組織なら、なお良いですね。","ENG":"Ideally, it would be another organization that is capable, yet relatively obscure.","TWN":"最好是實力出眾，而且還不為世人所知曉的組織。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 원, 할배 농담도 할 줄 알았어?","JPN":"ジジイ、冗談がうまいな。","ENG":"Well, old chap. I never took you for someone with a sense of humour!","TWN":"真是的，老頭也會開玩笑了？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 입맛에 딱 들어맞는 데가 퍽이나 있겠다.","JPN":"そんな条件にピッタリはまる組織なんてあるわけないだろ。","ENG":"Good luck trying to find a team like that in this lifetime.","TWN":"哪有這麼稱心如意的事情。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아뇨. 있습니다. 아가씨께서 직접 추천해 주시더군요.","JPN":"いいえ、あります。お嬢様が直々に推薦されました。","ENG":"No need for such luck. As a matter of fact, we've already found one. Lady Elizabeth made the recommendation herself.","TWN":"不，有。是小姐親自推薦的。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......엥?","JPN":"……えっ？","ENG":"Huh?","TWN":"……哼？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하핫. 코핀 컴퍼니라는 곳일세.","JPN":"ははっ。コフィンカンパニーというところだ。","ENG":"Hah hah! They call themselves the Coffin Company.","TWN":"哈哈，是一個叫科芬的公司。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋은 경험이 될 거야. 위장 신분을 하나 준비해 뒀으니 다녀와 보게.","JPN":"いい経験になるだろう。偽装する身分を用意しておいたから、行ってくるといい。","ENG":"I'm sure it'll be a great experience. We've prepared a cover identity for you. Off you go then.","TWN":"這是一個很好的機會，我們給你安排了一個假身份，你去吧。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 마침 잘 만났군!","JPN":"お、ちょうどいいところに！","ENG":"Oh, just the man I was looking for!","TWN":"喔，正好要找你！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그러니까...... 사장님이었지?","JPN":"ああそうだ……社長だったか？","ENG":"Erm... Boss, right?","TWN":"啊，你是……老闆吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하핫, 입사한 지도 꽤 됐는데 이제 알아볼 때도 되지 않았나?","JPN":"はははっ。入社してかなり経つから、そろそろ見慣れてほしいな。","ENG":"Hah hah. Isn't it about time you recognized me? It's been a while since you've joined our company, after all.","TWN":"哈哈哈，你進公司也很長一段時間了，也該記住我了吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};